const PROCESSING_FEE = 5;
const BLOCK_SIZE = 3;
const BLOCK_PRICE = 60;

const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

type Item = { type: string; material: string; enchantment: number; cursed: boolean };

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const componentBlockBaseFor = (count: number, type: string): number =>
  count === BLOCK_SIZE
    ? BLOCK_PRICE
    : count * BASE_PREMIUM_BY_ITEM_TYPE[type];

const componentsBaseFor = (items: Item[]): number => {
  const countsByType = new Map<string, number>();
  for (const item of items) {
    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
  }
  let total = 0;
  for (const [type, count] of countsByType) {
    total += componentBlockBaseFor(count, type);
  }
  return total;
};

const nonComponentBaseFor = (items: Item[]): number =>
  items.reduce((sum, item) => sum + BASE_PREMIUM_BY_ITEM_TYPE[item.type], 0);

export function quote(input: { yearsWithMHPCO: number; items: Item[] }): number {
  const components = input.items.filter(isComponent);
  const nonComponents = input.items.filter((item) => !isComponent(item));
  return nonComponentBaseFor(nonComponents) + componentsBaseFor(components) + PROCESSING_FEE;
}
